func TestBatchEvaluation(t *testing.T) {
	store := newMockFlagStore()
	store.flags["default:flag1"] = &flipt.Flag{
		NamespaceKey: "default",
		Key:          "flag1",
		Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		Enabled:      true,
	}
	store.flags["default:flag2"] = &flipt.Flag{
		NamespaceKey: "default",
		Key:          "flag2",
		Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		Enabled:      false,
	}

	grpcServer, grpcAddr := setupEvaluationServer(t, store)
	defer grpcServer.Stop()

	httpServer := setupGatewayHTTPServer(t, grpcAddr)
	defer httpServer.Close()

	batchReqBody := map[string]interface{}{
		"request_id": "batch-req-123",
		"requests": []map[string]interface{}{
			{
				"namespace_key": "default",
				"flag_key":      "flag1",
				"entity_id":     "user1",
			},
			{
				"namespace_key": "default",
				"flag_key":      "flag2",
				"entity_id":     "user2",
			},
		},
	}

	body, err := json.Marshal(batchReqBody)
	require.NoError(t, err)

	resp, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/batch", httpServer.URL),
		"application/json",
		bytes.NewReader(body),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		t.Fatalf("expected status 200 for batch request, got %d", resp.StatusCode)
